import React, { useState } from "react";

export default function HomePage() {
  const [input1, onChangeInput1] = useState('');
  const [input2, onChangeInput2] = useState('');
  const [input3, onChangeInput3] = useState('');
  const [input4, onChangeInput4] = useState('');
  const [input5, onChangeInput5] = useState('');

  const [toast, setToast] = useState(null);

  const showToast = (message) => {
    setToast(message);
    setTimeout(() => setToast(null), 2500);
  };

  return (
    <div className="min-h-screen flex justify-center bg-gray-100 py-10 relative">

      {/* Toast nổi */}
      {toast && (
        <div className="fixed top-10 right-10 bg-black text-white px-6 py-3 rounded-lg shadow-lg z-50 animate-slide-down">
          {toast}
        </div>
      )}

      <div className="flex flex-col items-center bg-white w-full max-w-[1200px] rounded-[10px] shadow-lg p-5">

        {/* Header */}
        <div className="flex items-center bg-[#88BCF8] w-full py-3 px-6 rounded-[10px] mb-8 justify-between">
          {/* Logo */}
          <img
            src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/iitooitd_expires_30_days.png"
            className="w-[120px] h-[110px] object-fill"
          />

          {/* Input tìm kiếm */}
          <input
            placeholder="Nhập để tìm kiếm"
            value={input1}
            onChange={(e) => onChangeInput1(e.target.value)}
            className="text-black bg-[#F6FEFF] text-base w-[350px] py-2 px-5 rounded-[50px] border-0"
          />

          {/* Biểu tượng bên phải */}
          <div className="flex items-center gap-4">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/qfk5vizv_expires_30_days.png"
              className="w-[50px] h-[38px] object-fill"
            />
            <div className="relative">
              <img
                src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/pt1vc4hr_expires_30_days.png"
                className="w-[47px] h-[69px]"
              />
              <img
                src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/rykqncqm_expires_30_days.png"
                className="w-[63px] h-[63px] absolute bottom-0 right-[-10px]"
              />
            </div>
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/l63q73r0_expires_30_days.png"
              className="w-[42px] h-[42px]"
            />
          </div>
        </div>

        {/* Body */}
        <div className="flex w-full gap-6">

          {/* Sidebar (5 biểu tượng gọn hơn) */}
          <div className="flex flex-col items-center bg-[#88BCF8] w-[72px] p-4 gap-6 rounded-[10px]">
            <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/od5pn9yq_expires_30_days.png" className="w-[42px] h-[42px]" />
            <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nxy76zef_expires_30_days.png" className="w-[42px] h-[42px]" />
            <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/8o6xqfxj_expires_30_days.png" className="w-[42px] h-[37px]" />
            <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/v47lki4u_expires_30_days.png" className="w-[42px] h-[42px]" />
            <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ebla58bn_expires_30_days.png" className="w-[42px] h-[42px]" />
          </div>

          {/* Main Feed */}
          <div className="flex flex-col items-center w-full gap-6">

            {/* Nút “Chào bạn” */}
            <button
              className="w-full bg-[#FFDEF8CF] py-3 rounded-[10px]"
              onClick={() => showToast("Xin chào bạn!")}>
              <span className="text-black text-xl">{"Chào bạn"}</span>
            </button>

            {/* Input gửi bài */}
            <div className="flex items-center bg-[#A2D3FF] py-3 px-6 rounded-[10px] w-full">
              <img
                src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/d7m3bryx_expires_30_days.png"
                className="w-[58px] h-[58px] mr-4"
              />
              <input
                placeholder="Hôm nay bạn thế nào chia sẻ với tui đi!!"
                value={input2}
                onChange={(e) => onChangeInput2(e.target.value)}
                className="text-black bg-[#F6FEFF] text-xl flex-1 py-2 px-4 rounded-[50px] border-0"
              />
              <button
                className="ml-4 bg-blue-400 text-white px-4 py-2 rounded-lg"
                onClick={() => {
                  if (input2.trim() !== "") {
                    showToast(`Bạn vừa gửi: "${input2}"`);
                    onChangeInput2('');
                    setTimeout(() => showToast("Bạn của bạn đăng tin"), 500);
                  }
                }}
              >
                Gửi
              </button>
            </div>

            {/* Các bài post */}
            {[1, 2, 3].map((i) => (
              <div key={i} className="flex flex-col bg-[#A2D3FF] w-full p-4 rounded-[10px] gap-4">
                <div className="flex items-center gap-4">
                  <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/oadiyd0v_expires_30_days.png" className="w-[58px] h-[51px]" />
                  <div className="flex flex-col">
                    <span className="text-black text-xl">{"Nickname"}</span>
                    <span className="text-black text-base">{"công khai"}</span>
                  </div>
                </div>
                <div className="flex gap-4">
                  <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nwti4bgy_expires_30_days.png" className="w-1/2 rounded-lg" />
                  <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/3cxpt7rg_expires_30_days.png" className="w-1/2 rounded-lg" />
                </div>
                <div className="flex items-center gap-4 mt-2">
                  <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/gyfive3m_expires_30_days.png" className="w-[39px] h-[45px] rounded-[10px]" />
                  <input placeholder="Bình luận" value={i === 1 ? input3 : i === 2 ? input4 : input5} onChange={(e) => i === 1 ? onChangeInput3(e.target.value) : i === 2 ? onChangeInput4(e.target.value) : onChangeInput5(e.target.value)} className="flex-1 py-2 px-4 rounded-lg text-black border-0" />
                </div>
              </div>
            ))}

          </div>
        </div>

      </div>

      <style>
        {`
          @keyframes slideDown {
            0% { opacity: 0; transform: translateY(-20px); }
            100% { opacity: 1; transform: translateY(0); }
          }
          .animate-slide-down {
            animation: slideDown 0.3s ease-out;
          }
        `}
      </style>
    </div>
  );
}
